// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-013: Metrics & Monitoring - Middleware for HTTP metrics
package middleware

import (
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
)

var (
	// HTTP metrics
	httpRequestsTotal = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"method", "endpoint", "status"},
	)

	httpRequestDuration = promauto.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"method", "endpoint"},
	)

	httpRequestSize = promauto.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_size_bytes",
			Help:    "HTTP request size in bytes",
			Buckets: prometheus.ExponentialBuckets(100, 10, 8),
		},
		[]string{"method", "endpoint"},
	)

	httpResponseSize = promauto.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_response_size_bytes",
			Help:    "HTTP response size in bytes",
			Buckets: prometheus.ExponentialBuckets(100, 10, 8),
		},
		[]string{"method", "endpoint"},
	)

	// Active requests gauge
	httpActiveRequests = promauto.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "http_active_requests",
			Help: "Number of active HTTP requests",
		},
		[]string{"method"},
	)

	// Error rate counters
	httpErrorsTotal = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_errors_total",
			Help: "Total number of HTTP errors",
		},
		[]string{"method", "endpoint", "status_code"},
	)
)

// MetricsMiddleware provides Prometheus metrics collection.
type MetricsMiddleware struct {
	excludePaths []string
}

// NewMetricsMiddleware creates a new metrics middleware.
func NewMetricsMiddleware(excludePaths ...string) *MetricsMiddleware {
	return &MetricsMiddleware{
		excludePaths: excludePaths,
	}
}

// shouldExclude checks if a path should be excluded from metrics.
func (mm *MetricsMiddleware) shouldExclude(path string) bool {
	for _, exclude := range mm.excludePaths {
		if path == exclude {
			return true
		}
	}
	return false
}

// Metrics returns the Gin middleware function for collecting metrics.
func (mm *MetricsMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if mm.shouldExclude(c.Request.URL.Path) {
			c.Next()
			return
		}

		start := time.Now()
		method := c.Request.Method
		endpoint := c.FullPath()
		if endpoint == "" {
			endpoint = "unknown"
		}

		// Track active requests
		httpActiveRequests.WithLabelValues(method).Inc()
		defer httpActiveRequests.WithLabelValues(method).Dec()

		// Get request size
		if c.Request.ContentLength > 0 {
			httpRequestSize.WithLabelValues(method, endpoint).Observe(float64(c.Request.ContentLength))
		}

		// Wrap the writer to capture response size
		wrappedWriter := &responseWriter{ResponseWriter: c.Writer, statusCode: http.StatusOK}
		c.Writer = wrappedWriter

		// Process request
		c.Next()

		// Record metrics
		duration := time.Since(start).Seconds()
		statusCode := strconv.Itoa(wrappedWriter.statusCode)

		httpRequestsTotal.WithLabelValues(method, endpoint, statusCode).Inc()
		httpRequestDuration.WithLabelValues(method, endpoint).Observe(duration)

		if wrappedWriter.written > 0 {
			httpResponseSize.WithLabelValues(method, endpoint).Observe(float64(wrappedWriter.written))
		}

		// Track errors (status >= 400)
		if wrappedWriter.statusCode >= 400 {
			httpErrorsTotal.WithLabelValues(method, endpoint, statusCode).Inc()
		}
	}
}

// responseWriter wraps gin.ResponseWriter to capture status code and size.
type responseWriter struct {
	gin.ResponseWriter
	statusCode int
	written    int64
}

func (w *responseWriter) WriteHeader(code int) {
	w.statusCode = code
	w.ResponseWriter.WriteHeader(code)
}

func (w *responseWriter) Write(data []byte) (int, error) {
	n, err := w.ResponseWriter.Write(data)
	w.written += int64(n)
	return n, err
}

func (w *responseWriter) WriteString(s string) (int, error) {
	n, err := w.ResponseWriter.WriteString(s)
	w.written += int64(n)
	return n, err
}

// GetHTTPRequestsTotal returns the HTTP requests total counter.
func GetHTTPRequestsTotal() *prometheus.CounterVec {
	return httpRequestsTotal
}

// GetHTTPRequestDuration returns the HTTP request duration histogram.
func GetHTTPRequestDuration() *prometheus.HistogramVec {
	return httpRequestDuration
}

// GetHTTPActiveRequests returns the active requests gauge.
func GetHTTPActiveRequests() *prometheus.GaugeVec {
	return httpActiveRequests
}

