		router.ServeHTTP(w, req)
		assert.Equal(t, http.StatusOK, w.Code)
	}
}

func TestMetricsMiddleware_DifferentMethods(t *testing.T) {
	mm := NewMetricsMiddleware()

	router := setupValidationTest()
	router.Use(mm.Middleware())

	router.GET("/resource", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"method": "GET"})
	})
	router.POST("/resource", func(c *gin.Context) {
		c.JSON(http.StatusCreated, gin.H{"method": "POST"})
	})
	router.PUT("/resource", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"method": "PUT"})
	})
	router.DELETE("/resource", func(c *gin.Context) {
		c.JSON(http.StatusNoContent, gin.H{"method": "DELETE"})
	})

	methods := []string{"GET", "POST", "PUT", "DELETE"}
	for _, method := range methods {
		w := httptest.NewRecorder()
		req, _ := http.NewRequest(method, "/resource", nil)
		router.ServeHTTP(w, req)
		assert.True(t, w.Code == http.StatusOK || w.Code == http.StatusCreated || w.Code == http.StatusNoContent)
	}
}

// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-014: Circuit Breaker - Middleware for resilience
package middleware

import (
	"errors"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
)

// CircuitBreakerState represents the state of a circuit breaker.
type CircuitBreakerState int

const (
	// StateClosed allows all requests.
	StateClosed CircuitBreakerState = 0
	// StateOpen rejects all requests.
	StateOpen CircuitBreakerState = 1
	// StateHalfOpen allows a limited number of requests to test recovery.
	StateHalfOpen CircuitBreakerState = 2
)

func (s CircuitBreakerState) String() string {
	switch s {
	case StateClosed:
		return "closed"
	case StateOpen:
		return "open"
	case StateHalfOpen:
		return "half-open"
	default:
		return "unknown"
	}
}

// CircuitBreakerConfig configures the circuit breaker.
type CircuitBreakerConfig struct {
	// Name identifies the circuit breaker.
	Name string
	// MaxFailures before opening the circuit.
	MaxFailures uint32
	// Timeout when the circuit is open.
	Timeout time.Duration
	// MaxRequests in half-open state to test recovery.
	MaxRequests uint32
	// Interval to clear counts when closed.
	Interval time.Duration
	// ReadyToTrip is called with failure count to determine if circuit should open.
	ReadyToTrip func(count uint32) bool
	// OnStateChange is called when circuit state changes.
	OnStateChange func(name string, from CircuitBreakerState, to CircuitBreakerState)
	// IsSuccessful determines if an error is considered a failure.
	IsSuccessful func(err error) bool
}

// CircuitBreaker implements the circuit breaker pattern.
type CircuitBreaker struct {
	name          string
	maxFailures   uint32
	timeout       time.Duration
	maxRequests   uint32
	interval      time.Duration
	readyToTrip   func(count uint32) bool
	onStateChange func(name string, from CircuitBreakerState, to CircuitBreakerState)
	isSuccessful  func(err error) bool

	mu                sync.Mutex
	state             CircuitBreakerState
	generation        uint64
	counts            Counts
	expiry            time.Time
	halfOpenAttempts  uint32
}

// Counts holds the circuit breaker counts.
type Counts struct {
	Requests             uint32
	TotalSuccesses       uint32
	TotalFailures        uint32
	ConsecutiveSuccesses uint32
	ConsecutiveFailures  uint32
}

// ErrCircuitBreakerOpen is returned when the circuit breaker is open.
var ErrCircuitBreakerOpen = errors.New("circuit breaker is open")

// ErrTooManyRequests is returned when half-open and too many requests.
var ErrTooManyRequests = errors.New("too many requests in half-open state")

// DefaultCircuitBreakerConfig returns a default configuration.
func DefaultCircuitBreakerConfig(name string) CircuitBreakerConfig {
	return CircuitBreakerConfig{
		Name:        name,
		MaxFailures: 5,
		Timeout:     30 * time.Second,
		MaxRequests: 3,
		Interval:    0,
		ReadyToTrip: func(count uint32) bool {
			return count >= 5
		},
		IsSuccessful: func(err error) bool {
			return err == nil
		},
	}
}

// NewCircuitBreaker creates a new circuit breaker.
func NewCircuitBreaker(config CircuitBreakerConfig) *CircuitBreaker {
	cb := &CircuitBreaker{
		name:          config.Name,
		maxFailures:   config.MaxFailures,
		timeout:       config.Timeout,
		maxRequests:   config.MaxRequests,
		interval:      config.Interval,
		readyToTrip:   config.ReadyToTrip,
		onStateChange: config.OnStateChange,
		isSuccessful:  config.IsSuccessful,
		state:         StateClosed,
		generation:    0,
		counts:        Counts{},
	}

	if cb.readyToTrip == nil {
		cb.readyToTrip = func(count uint32) bool {
			return count >= cb.maxFailures
		}
	}

	if cb.isSuccessful == nil {
		cb.isSuccessful = func(err error) bool {
			return err == nil
		}
	}

	if cb.interval == 0 {
		cb.interval = time.Duration(0)
	}

	return cb
}

// State returns the current state of the circuit breaker.
func (cb *CircuitBreaker) State() CircuitBreakerState {
	cb.mu.Lock()
	defer cb.mu.Unlock()

	now := time.Now()
	state, _ := cb.currentState(now)
	return state
}

// currentState returns the current state and generation.
func (cb *CircuitBreaker) currentState(now time.Time) (CircuitBreakerState, uint64) {
	switch cb.state {
	case StateClosed:
		if cb.interval != 0 && !cb.expiry.IsZero() && cb.expiry.Before(now) {
			cb.toNewGeneration(now)
		}
	case StateOpen:
		if cb.expiry.Before(now) {
			cb.setState(StateHalfOpen, now)
		}
	}
	return cb.state, cb.generation
}

// setState changes the circuit breaker state.
func (cb *CircuitBreaker) setState(state CircuitBreakerState, now time.Time) {
	if cb.state == state {
		return
	}

	prev := cb.state
	cb.state = state
	cb.toNewGeneration(now)

	if cb.onStateChange != nil {
		cb.onStateChange(cb.name, prev, state)
	}
}

// toNewGeneration resets counts and increments generation.
func (cb *CircuitBreaker) toNewGeneration(now time.Time) {
	cb.generation++
	cb.counts = Counts{}
	cb.halfOpenAttempts = 0

	var zero time.Time
	switch cb.state {
	case StateClosed:
		if cb.interval == 0 {
			cb.expiry = zero
		} else {
			cb.expiry = now.Add(cb.interval)
		}
	case StateOpen:
		cb.expiry = now.Add(cb.timeout)
	case StateHalfOpen:
		cb.expiry = now
	}
}

// Call executes the given function with circuit breaker protection.
func (cb *CircuitBreaker) Call(fn func() error) error {
	generation, err := cb.beforeCall()
	if err != nil {
		return err
	}

	return cb.afterCall(generation, fn())
}

// beforeCall is called before the protected function.
func (cb *CircuitBreaker) beforeCall() (uint64, error) {
	cb.mu.Lock()
	defer cb.mu.Unlock()

	now := time.Now()
	state, generation := cb.currentState(now)

	switch state {
	case StateClosed:
		return generation, nil
	case StateOpen:
		return 0, ErrCircuitBreakerOpen
	case StateHalfOpen:
		if cb.halfOpenAttempts >= cb.maxRequests {
			return 0, ErrTooManyRequests
		}
		cb.halfOpenAttempts++
		return generation, nil
	default:
		return 0, fmt.Errorf("unknown circuit breaker state: %v", state)
	}
}

// afterCall is called after the protected function.
func (cb *CircuitBreaker) afterCall(generation uint64, err error) error {
	cb.mu.Lock()
	defer cb.mu.Unlock()

	now := time.Now()
	state, currentGeneration := cb.currentState(now)

	if generation != currentGeneration {
		return nil
	}

	if cb.isSuccessful(err) {
		cb.onSuccess(state, now)
	} else {
		cb.onFailure(state, now)
	}

	return err
}

// onSuccess handles successful calls.
func (cb *CircuitBreaker) onSuccess(state CircuitBreakerState, now time.Time) {
	switch state {
	case StateClosed:
		cb.counts.OnSuccess()
	case StateHalfOpen:
		cb.counts.OnSuccess()
		if cb.counts.ConsecutiveSuccesses >= cb.maxRequests {
			cb.setState(StateClosed, now)
		}
	}
}

// onFailure handles failed calls.
func (cb *CircuitBreaker) onFailure(state CircuitBreakerState, now time.Time) {
	switch state {
	case StateClosed:
		cb.counts.OnFailure()
		if cb.readyToTrip(cb.counts.ConsecutiveFailures) {
			cb.setState(StateOpen, now)
		}
	case StateHalfOpen:
		cb.setState(StateOpen, now)
	}
}

// Counts methods

// OnSuccess updates counts on success.
func (c *Counts) OnSuccess() {
	c.Requests++
	c.TotalSuccesses++
	c.ConsecutiveSuccesses++
	c.ConsecutiveFailures = 0
}

// OnFailure updates counts on failure.
func (c *Counts) OnFailure() {
	c.Requests++
	c.TotalFailures++
	c.ConsecutiveSuccesses = 0
	c.ConsecutiveFailures++
}

// CircuitBreakerMiddleware provides circuit breaker as Gin middleware.
type CircuitBreakerMiddleware struct {
	breaker *CircuitBreaker
}

// NewCircuitBreakerMiddleware creates a new circuit breaker middleware.
func NewCircuitBreakerMiddleware(config CircuitBreakerConfig) *CircuitBreakerMiddleware {
	return &CircuitBreakerMiddleware{
		breaker: NewCircuitBreaker(config),
	}
}

// Middleware returns the Gin middleware function.
func (cbm *CircuitBreakerMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		err := cbm.breaker.Call(func() error {
			c.Next()
			if len(c.Errors) > 0 {
				return c.Errors.Last()
			}
			return nil
		})

		if err == ErrCircuitBreakerOpen {
			c.AbortWithStatusJSON(http.StatusServiceUnavailable, gin.H{
				"error":   "service temporarily unavailable",
				"message": "circuit breaker is open",
			})
			return
		}

		if err == ErrTooManyRequests {
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error":   "too many requests",
				"message": "circuit breaker is half-open, please retry",
			})
			return
		}
	}
}

// State returns the current state of the circuit breaker.
func (cbm *CircuitBreakerMiddleware) State() CircuitBreakerState {
	return cbm.breaker.State()
}

// CircuitBreakerManager manages multiple circuit breakers.
type CircuitBreakerManager struct {
	breakers map[string]*CircuitBreaker
	mu       sync.RWMutex
}

// NewCircuitBreakerManager creates a new circuit breaker manager.
func NewCircuitBreakerManager() *CircuitBreakerManager {
	return &CircuitBreakerManager{
		breakers: make(map[string]*CircuitBreaker),
	}
}

// GetOrCreate gets or creates a circuit breaker.
func (cbm *CircuitBreakerManager) GetOrCreate(name string, config CircuitBreakerConfig) *CircuitBreaker {
	cbm.mu.RLock()
	if cb, exists := cbm.breakers[name]; exists {
		cbm.mu.RUnlock()
		return cb
	}
	cbm.mu.RUnlock()

	cbm.mu.Lock()
	defer cbm.mu.Unlock()

	// Double-check after acquiring write lock
	if cb, exists := cbm.breakers[name]; exists {
		return cb
	}

	config.Name = name
	cb := NewCircuitBreaker(config)
	cbm.breakers[name] = cb
	return cb
}

// Get gets a circuit breaker by name.
func (cbm *CircuitBreakerManager) Get(name string) (*CircuitBreaker, bool) {
	cbm.mu.RLock()
	defer cbm.mu.RUnlock()
	cb, exists := cbm.breakers[name]
	return cb, exists
}

// Remove removes a circuit breaker.
func (cbm *CircuitBreakerManager) Remove(name string) {
	cbm.mu.Lock()
	defer cbm.mu.Unlock()
	delete(cbm.breakers, name)
}

// List returns all circuit breaker names.
func (cbm *CircuitBreakerManager) List() []string {
	cbm.mu.RLock()
	defer cbm.mu.RUnlock()

	names := make([]string, 0, len(cbm.breakers))
	for name := range cbm.breakers {
		names = append(names, name)
	}
	return names
}

// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-015: API Rate Limiting - Middleware for rate limiting
package middleware

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
)

// RateLimiterStrategy defines the rate limiting strategy.
type RateLimiterStrategy int

const (
	// FixedWindow uses a fixed time window.
	FixedWindow RateLimiterStrategy = 0
	// SlidingWindow uses a sliding time window.
	SlidingWindow RateLimiterStrategy = 1
	// TokenBucket uses a token bucket algorithm.
	TokenBucket RateLimiterStrategy = 2
)

// RateLimiterConfig configures the rate limiter.
type RateLimiterConfig struct {
	// Requests per window.
	Requests int
	// Window duration.
	Window time.Duration
	// Strategy to use.
	Strategy RateLimiterStrategy
	// KeyFunc extracts the client identifier from the request.
	KeyFunc func(c *gin.Context) string
	// SkipFunc determines if rate limiting should be skipped.
	SkipFunc func(c *gin.Context) bool
	// OnLimitReached is called when rate limit is exceeded.
	OnLimitReached func(c *gin.Context, retryAfter time.Duration)
}

// DefaultKeyFunc extracts client IP or request ID.
func DefaultKeyFunc(c *gin.Context) string {
	// Try to get client ID from header
	if clientID := c.GetHeader("X-Client-ID"); clientID != "" {
		return clientID
	}
	// Try to get API key from Authorization header
	if apiKey := c.GetHeader("X-API-Key"); apiKey != "" {
		return apiKey
	}
	// Fall back to client IP
	return c.ClientIP()
}

// DefaultRateLimiterConfig returns a default configuration.
func DefaultRateLimiterConfig() RateLimiterConfig {
	return RateLimiterConfig{
		Requests: 100,
		Window:   time.Minute,
		Strategy: SlidingWindow,
		KeyFunc:  DefaultKeyFunc,
		SkipFunc: func(c *gin.Context) bool {
			// Skip health checks
			return c.Request.URL.Path == "/health" ||
				c.Request.URL.Path == "/health/live" ||
				c.Request.URL.Path == "/health/ready"
		},
		OnLimitReached: func(c *gin.Context, retryAfter time.Duration) {
			c.Header("Retry-After", fmt.Sprintf("%d", int(retryAfter.Seconds())))
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error":       "rate limit exceeded",
				"retry_after": int(retryAfter.Seconds()),
			})
		},
	}
}

// RateLimiterMiddleware provides rate limiting.
type RateLimiterMiddleware struct {
	config       RateLimiterConfig
	fixedWindows map[string]*fixedWindow
	slidingWindows map[string]*slidingWindow
	tokenBuckets   map[string]*tokenBucket
	mu             sync.RWMutex
}

// NewRateLimiterMiddleware creates a new rate limiter middleware.
func NewRateLimiterMiddleware(config RateLimiterConfig) *RateLimiterMiddleware {
	return &RateLimiterMiddleware{
		config:         config,
		fixedWindows:   make(map[string]*fixedWindow),
		slidingWindows: make(map[string]*slidingWindow),
		tokenBuckets:   make(map[string]*tokenBucket),
	}
}

// fixedWindow implements fixed window rate limiting.
type fixedWindow struct {
	count      int
	windowStart time.Time
	mu         sync.Mutex
}

// slidingWindow implements sliding window rate limiting.
type slidingWindow struct {
	requests   []time.Time
	mu         sync.Mutex
}

// tokenBucket implements token bucket rate limiting.
type tokenBucket struct {
	tokens     float64
	lastUpdate time.Time
	mu         sync.Mutex
}

// Middleware returns the Gin middleware function.
func (rlm *RateLimiterMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Check if should skip
		if rlm.config.SkipFunc != nil && rlm.config.SkipFunc(c) {
			c.Next()
			return
		}

		// Get client key
		key := rlm.config.KeyFunc(c)
		if key == "" {
			key = uuid.New().String()
		}

		// Check rate limit based on strategy
		allowed, retryAfter := rlm.allow(key)

		if !allowed {
			if rlm.config.OnLimitReached != nil {
				rlm.config.OnLimitReached(c, retryAfter)
			}
			return
		}

		c.Next()
	}
}

// allow checks if a request is allowed.
func (rlm *RateLimiterMiddleware) allow(key string) (bool, time.Duration) {
	switch rlm.config.Strategy {
	case FixedWindow:
		return rlm.allowFixedWindow(key)
	case SlidingWindow:
		return rlm.allowSlidingWindow(key)
	case TokenBucket:
		return rlm.allowTokenBucket(key)
	default:
		return rlm.allowSlidingWindow(key)
	}
}

// allowFixedWindow implements fixed window rate limiting.
func (rlm *RateLimiterMiddleware) allowFixedWindow(key string) (bool, time.Duration) {
	rlm.mu.Lock()
	defer rlm.mu.Unlock()

	now := time.Now()
	window, exists := rlm.fixedWindows[key]

	if !exists || now.Sub(window.windowStart) >= rlm.config.Window {
		// New window
		rlm.fixedWindows[key] = &fixedWindow{
			count:       1,
			windowStart: now,
		}
		return true, 0
	}

	window.mu.Lock()
	defer window.mu.Unlock()

	if window.count >= rlm.config.Requests {
		// Window full, calculate retry after
		retryAfter := rlm.config.Window - now.Sub(window.windowStart)
		return false, retryAfter
	}

	window.count++
	return true, 0
}

// allowSlidingWindow implements sliding window rate limiting.
func (rlm *RateLimiterMiddleware) allowSlidingWindow(key string) (bool, time.Duration) {
	rlm.mu.Lock()
	defer rlm.mu.Unlock()

	now := time.Now()
	window, exists := rlm.slidingWindows[key]

	if !exists {
		rlm.slidingWindows[key] = &slidingWindow{
			requests: []time.Time{now},
		}
		return true, 0
	}

	window.mu.Lock()
	defer window.mu.Unlock()

	// Remove requests outside the window
	cutoff := now.Add(-rlm.config.Window)
	validRequests := make([]time.Time, 0)
	for _, req := range window.requests {
		if req.After(cutoff) {
			validRequests = append(validRequests, req)
		}
	}

	if len(validRequests) >= rlm.config.Requests {
		// Window full, calculate retry after
		if len(validRequests) > 0 {
			retryAfter := validRequests[0].Add(rlm.config.Window).Sub(now)
			return false, retryAfter
		}
		return false, rlm.config.Window
	}

	// Add current request
	validRequests = append(validRequests, now)
	window.requests = validRequests

	return true, 0
}

// allowTokenBucket implements token bucket rate limiting.
func (rlm *RateLimiterMiddleware) allowTokenBucket(key string) (bool, time.Duration) {
	rlm.mu.Lock()
	defer rlm.mu.Unlock()

	now := time.Now()
	bucket, exists := rlm.tokenBuckets[key]

	if !exists {
		rlm.tokenBuckets[key] = &tokenBucket{
			tokens:     float64(rlm.config.Requests) - 1,
			lastUpdate: now,
		}
		return true, 0
	}

	bucket.mu.Lock()
	defer bucket.mu.Unlock()

	// Calculate tokens to add
	elapsed := now.Sub(bucket.lastUpdate).Seconds()
	rate := float64(rlm.config.Requests) / rlm.config.Window.Seconds()
	bucket.tokens += elapsed * rate

	if bucket.tokens > float64(rlm.config.Requests) {
		bucket.tokens = float64(rlm.config.Requests)
	}

	bucket.lastUpdate = now

	if bucket.tokens < 1 {
		// No tokens available
		retryAfter := time.Duration((1 - bucket.tokens) / rate * float64(time.Second))
		return false, retryAfter
	}

	bucket.tokens--
	return true, 0
}

// GetRemaining returns the remaining requests for a key.
func (rlm *RateLimiterMiddleware) GetRemaining(key string) int {
	switch rlm.config.Strategy {
	case FixedWindow:
		return rlm.getRemainingFixedWindow(key)
	case SlidingWindow:
		return rlm.getRemainingSlidingWindow(key)
	case TokenBucket:
		return rlm.getRemainingTokenBucket(key)
	default:
		return rlm.getRemainingSlidingWindow(key)
	}
}

func (rlm *RateLimiterMiddleware) getRemainingFixedWindow(key string) int {
	rlm.mu.RLock()
	defer rlm.mu.RUnlock()

	window, exists := rlm.fixedWindows[key]
	if !exists {
		return rlm.config.Requests
	}

	if time.Since(window.windowStart) >= rlm.config.Window {
		return rlm.config.Requests
	}

	return rlm.config.Requests - window.count
}

func (rlm *RateLimiterMiddleware) getRemainingSlidingWindow(key string) int {
	rlm.mu.RLock()
	defer rlm.mu.RUnlock()

	window, exists := rlm.slidingWindows[key]
	if !exists {
		return rlm.config.Requests
	}

	now := time.Now()
	cutoff := now.Add(-rlm.config.Window)

	count := 0
	for _, req := range window.requests {
		if req.After(cutoff) {
			count++
		}
	}

	return rlm.config.Requests - count
}

func (rlm *RateLimiterMiddleware) getRemainingTokenBucket(key string) int {
	rlm.mu.RLock()
	defer rlm.mu.RUnlock()

	bucket, exists := rlm.tokenBuckets[key]
	if !exists {
		return rlm.config.Requests
	}

	now := time.Now()
	elapsed := now.Sub(bucket.lastUpdate).Seconds()
	rate := float64(rlm.config.Requests) / rlm.config.Window.Seconds()
	tokens := bucket.tokens + elapsed*rate

	if tokens > float64(rlm.config.Requests) {
		tokens = float64(rlm.config.Requests)
	}

	return int(tokens)
}

// Cleanup removes old entries.
func (rlm *RateLimiterMiddleware) Cleanup() {
	rlm.mu.Lock()
	defer rlm.mu.Unlock()

	now := time.Now()
	window := rlm.config.Window * 2

	// Clean fixed windows
	for key, fw := range rlm.fixedWindows {
		if now.Sub(fw.windowStart) >= window {
			delete(rlm.fixedWindows, key)
		}
	}

	// Clean sliding windows
	cutoff := now.Add(-window)
	for key, sw := range rlm.slidingWindows {
		sw.mu.Lock()
		valid := make([]time.Time, 0)
		for _, req := range sw.requests {
			if req.After(cutoff) {
				valid = append(valid, req)
			}
		}
		sw.requests = valid
		sw.mu.Unlock()

		if len(sw.requests) == 0 {
			delete(rlm.slidingWindows, key)
		}
	}

	// Clean token buckets
	for key, tb := range rlm.tokenBuckets {
		if now.Sub(tb.lastUpdate) >= window {
			delete(rlm.tokenBuckets, key)
		}
	}
}

// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-016: Distributed Tracing - Middleware for request tracing
package middleware

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
)

// TraceConfig configures the tracing middleware.
type TraceConfig struct {
	// ServiceName identifies this service in traces.
	ServiceName string
	// ServiceVersion is the version of this service.
	ServiceVersion string
	// TraceHeader is the HTTP header for trace ID.
	TraceHeader string
	// SpanHeader is the HTTP header for span ID.
	SpanHeader string
	// SampleRate is the sampling rate (0.0 to 1.0).
	SampleRate float64
	// ExportFunc exports spans.
	ExportFunc func(span *Span)
}

// Span represents a trace span.
type Span struct {
	TraceID      string            `json:"trace_id"`
	SpanID       string            `json:"span_id"`
	ParentSpanID string            `json:"parent_span_id,omitempty"`
	Name         string            `json:"name"`
	Service      string            `json:"service"`
	Version      string            `json:"version"`
	StartTime    time.Time         `json:"start_time"`
	EndTime      time.Time         `json:"end_time,omitempty"`
	Duration     time.Duration     `json:"duration,omitempty"`
	Tags         map[string]string `json:"tags,omitempty"`
	Events       []SpanEvent       `json:"events,omitempty"`
	Status       SpanStatus        `json:"status"`
}

// SpanEvent represents an event within a span.
type SpanEvent struct {
	Name       string            `json:"name"`
	Timestamp  time.Time         `json:"timestamp"`
	Attributes map[string]string `json:"attributes,omitempty"`
}

// SpanStatus represents the span status.
type SpanStatus int

const (
	// SpanStatusUnset is the default status.
	SpanStatusUnset SpanStatus = 0
	// SpanStatusOK indicates success.
	SpanStatusOK SpanStatus = 1
	// SpanStatusError indicates an error.
	SpanStatusError SpanStatus = 2
)

// DefaultTraceConfig returns a default configuration.
func DefaultTraceConfig() TraceConfig {
	return TraceConfig{
		ServiceName:    "agentcube",
		ServiceVersion: "1.0.0",
		TraceHeader:    "X-Request-ID",
		SpanHeader:     "X-Span-ID",
		SampleRate:     1.0,
		ExportFunc:     defaultExportFunc,
	}
}

func defaultExportFunc(span *Span) {
	// Default: do nothing
	// In production, implement export to Jaeger/Zipkin/OTLP
	_ = span
}

// TracingMiddleware provides distributed tracing.
type TracingMiddleware struct {
	config TraceConfig
}

// NewTracingMiddleware creates a new tracing middleware.
func NewTracingMiddleware(config TraceConfig) *TracingMiddleware {
	return &TracingMiddleware{
		config: config,
	}
}

// Middleware returns the Gin middleware function.
func (tm *TracingMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Extract or generate trace ID
		traceID := c.GetHeader(tm.config.TraceHeader)
		if traceID == "" {
			traceID = generateTraceID()
		}

		// Extract or generate span ID
		parentSpanID := c.GetHeader(tm.config.SpanHeader)
		spanID := generateSpanID()

		// Set headers for downstream services
		c.Header(tm.config.TraceHeader, traceID)
		c.Header(tm.config.SpanHeader, spanID)

		// Create span
		span := &Span{
			TraceID:      traceID,
			SpanID:       spanID,
			ParentSpanID: parentSpanID,
			Name:         fmt.Sprintf("%s %s", c.Request.Method, c.FullPath()),
			Service:      tm.config.ServiceName,
			Version:      tm.config.ServiceVersion,
			StartTime:    time.Now(),
			Tags: map[string]string{
				"http.method":      c.Request.Method,
				"http.path":        c.FullPath(),
				"http.client_ip":   c.ClientIP(),
				"http.user_agent":  c.Request.UserAgent(),
			},
			Status: SpanStatusUnset,
		}

		// Store in context
		ctx := context.WithValue(c.Request.Context(), spanContextKey, span)
		c.Request = c.Request.WithContext(ctx)

		// Add to Gin context
		c.Set("span", span)

		// Process request
		c.Next()

		// Complete span
		span.EndTime = time.Now()
		span.Duration = span.EndTime.Sub(span.StartTime)

		// Add response tags
		span.Tags["http.status_code"] = fmt.Sprintf("%d", c.Writer.Status())
		span.Tags["http.response_size"] = fmt.Sprintf("%d", c.Writer.Size())

		// Set status based on response
		if c.Writer.Status() >= 400 {
			span.Status = SpanStatusError
		} else {
			span.Status = SpanStatusOK
		}

		// Export span
		tm.exportSpan(span)
	}
}

// exportSpan exports a span.
func (tm *TracingMiddleware) exportSpan(span *Span) {
	// Sampling
	if tm.config.SampleRate < 1.0 && !shouldSample(span.TraceID, tm.config.SampleRate) {
		return
	}

	if tm.config.ExportFunc != nil {
		tm.config.ExportFunc(span)
	}
}

// shouldSample determines if a span should be sampled.
func shouldSample(traceID string, rate float64) bool {
	if rate >= 1.0 {
		return true
	}
	if rate <= 0.0 {
		return false
	}

	// Use trace ID for consistent sampling
	var hash uint64
	for _, b := range []byte(traceID) {
		hash = hash*31 + uint64(b)
	}
	return float64(hash%1000)/1000.0 < rate
}

// Context key for span
var spanContextKey = &contextKey{"span"}

type contextKey struct {
	name string
}

// GetSpanFromContext retrieves the span from context.
func GetSpanFromContext(ctx context.Context) *Span {
	if span, ok := ctx.Value(spanContextKey).(*Span); ok {
		return span
	}
	return nil
}

// GetSpanFromGin retrieves the span from Gin context.
func GetSpanFromGin(c *gin.Context) *Span {
	if span, exists := c.Get("span"); exists {
		if s, ok := span.(*Span); ok {
			return s
		}
	}
	return nil
}

// AddEvent adds an event to the current span.
func AddEvent(c *gin.Context, name string, attributes map[string]string) {
	span := GetSpanFromGin(c)
	if span == nil {
		return
	}

	span.Events = append(span.Events, SpanEvent{
		Name:       name,
		Timestamp:  time.Now(),
		Attributes: attributes,
	})
}

// AddTag adds a tag to the current span.
func AddTag(c *gin.Context, key, value string) {
	span := GetSpanFromGin(c)
	if span == nil {
		return
	}

	if span.Tags == nil {
		span.Tags = make(map[string]string)
	}
	span.Tags[key] = value
}

// SetSpanStatus sets the status of the current span.
func SetSpanStatus(c *gin.Context, status SpanStatus) {
	span := GetSpanFromGin(c)
	if span == nil {
		return
	}
	span.Status = status
}

// ChildSpan creates a child span.
func ChildSpan(c *gin.Context, name string) *Span {
	parentSpan := GetSpanFromGin(c)
	if parentSpan == nil {
		return nil
	}

	child := &Span{
		TraceID:      parentSpan.TraceID,
		SpanID:       generateSpanID(),
		ParentSpanID: parentSpan.SpanID,
		Name:         name,
		Service:      parentSpan.Service,
		Version:      parentSpan.Version,
		StartTime:    time.Now(),
		Tags:         make(map[string]string),
		Status:       SpanStatusUnset,
	}

	return child
}

// FinishSpan finishes a span.
func FinishSpan(span *Span, exportFunc func(*Span)) {
	if span == nil {
		return
	}

	span.EndTime = time.Now()
	span.Duration = span.EndTime.Sub(span.StartTime)

	if exportFunc != nil {
		exportFunc(span)
	}
}

// generateTraceID generates a new trace ID.
func generateTraceID() string {
	return generateRandomHex(16) // 32 hex chars = 128 bits
}

// generateSpanID generates a new span ID.
func generateSpanID() string {
	return generateRandomHex(8) // 16 hex chars = 64 bits
}

// generateRandomHex generates random hex string.
func generateRandomHex(bytes int) string {
	buf := make([]byte, bytes)
	if _, err := io.ReadFull(rand.Reader, buf); err != nil {
		// Fallback to timestamp-based ID
		return fmt.Sprintf("%x", time.Now().UnixNano())
	}
	return hex.EncodeToString(buf)
}

