// InjectTraceContext injects trace context into HTTP headers.
func InjectTraceContext(ctx context.Context, req *http.Request) {
	span := GetSpanFromContext(ctx)
	if span == nil {
		return
	}

	req.Header.Set("X-Request-ID", span.TraceID)
	req.Header.Set("X-Span-ID", span.SpanID)
	req.Header.Set("X-Service-Name", span.Service)
	req.Header.Set("X-Service-Version", span.Version)
}

// ExtractTraceContext extracts trace context from HTTP headers.
func ExtractTraceContext(req *http.Request) *TraceContext {
	return &TraceContext{
		TraceID:      req.Header.Get("X-Request-ID"),
		SpanID:       req.Header.Get("X-Span-ID"),
