		Type:      eventType,
		Timestamp: time.Now(),
	}

	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		return fmt.Errorf("failed to marshal payload: %w", err)
	}
	event.Payload = payloadBytes

	// Dispatch asynchronously
	for _, webhook := range webhooks {
		if !webhook.Active {
			continue
		}
		go m.send(webhook, event)
	}

	return nil
