func (m *Manager) send(webhook *Webhook, event *Event) error {
	payload, err := json.Marshal(event)
	if err != nil {
		return err
	}

	req, err := http.NewRequest("POST", webhook.URL, bytes.NewBuffer(payload))
	if err != nil {
		return err
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-Webhook-ID", webhook.ID)
	req.Header.Set("X-Event-ID", event.ID)
	req.Header.Set("X-Event-Type", event.Type)
	req.Header.Set("X-Webhook-Timestamp", event.Timestamp.Format(time.RFC3339))

	// Add signature
	if webhook.Secret != "" {
		signature := generateSignature(payload, webhook.Secret)
		req.Header.Set("X-Webhook-Signature", signature)
	}

	// Add custom headers
	for key, value := range webhook.Headers {
		req.Header.Set(key, value)
	}

	// Retry with exponential backoff
	retryDelay := webhook.RetryConfig.RetryDelay
	var lastErr error

	for i := 0; i <= webhook.RetryConfig.MaxRetries; i++ {
		resp, err := m.client.Do(req)
		if err != nil {
			lastErr = err
			if i < webhook.RetryConfig.MaxRetries {
				time.Sleep(retryDelay)
				retryDelay = time.Duration(float64(retryDelay) * webhook.RetryConfig.BackoffRate)
				if retryDelay > webhook.RetryConfig.MaxDelay {
					retryDelay = webhook.RetryConfig.MaxDelay
				}
			}
			continue
		}
		resp.Body.Close()

		// Success
		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
			m.updateWebhookStatus(webhook, true)
			return nil
		}

		lastErr = fmt.Errorf("webhook returned status %d", resp.StatusCode)

		// Don't retry on 4xx errors (client errors)
		if resp.StatusCode >= 400 && resp.StatusCode < 500 {
			break
		}

