	now := time.Now()
	webhook.LastUsedAt = &now

	if success {
		webhook.FailureCount = 0
	} else {
		webhook.FailureCount++
	}

	// Deactivate after too many failures
	if webhook.FailureCount >= 10 {
		webhook.Active = false
	}

	webhook.UpdatedAt = now
	m.store.Update(webhook)
}

// generateSignature generates HMAC signature for webhook payload.
func generateSignature(payload []byte, secret string) string {
	mac := hmac.New(sha256.New, []byte(secret))
	mac.Write(payload)
	return hex.EncodeToString(mac.Sum(nil))
}

// VerifySignature verifies webhook signature.
func VerifySignature(payload []byte, signature, secret string) bool {
	expected := generateSignature(payload, secret)
	return hmac.Equal([]byte(signature), []byte(expected))
}

// WebhookAuthMiddleware provides webhook authentication middleware.
type WebhookAuthMiddleware struct {
	secret string
}

// NewWebhookAuthMiddleware creates a new webhook auth middleware.
func NewWebhookAuthMiddleware(secret string) *WebhookAuthMiddleware {
	return &WebhookAuthMiddleware{
		secret: secret,
	}
}

// Middleware returns the Gin middleware function for webhook signature verification.
func (wam *WebhookAuthMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Skip if no secret configured
		if wam.secret == "" {
			c.Next()
			return
		}

		signature := c.GetHeader("X-Webhook-Signature")
		if signature == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "missing webhook signature",
			})
			return
		}

		// Read body
		body, err := c.GetRawData()
		if err != nil {
			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{
				"error": "failed to read request body",
			})
			return
		}

		// Verify signature
		if !VerifySignature(body, signature, wam.secret) {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "invalid webhook signature",
			})
			return
		}

		// Restore body for next handlers
		c.Request.Body = bytes.NewBuffer(body)
		c.Next()
	}
}

// Handler handles incoming webhooks.
type Handler struct {
	manager *Manager
}

// NewHandler creates a new webhook handler.
func NewHandler(manager *Manager) *Handler {
	return &Handler{
		manager: manager,
	}
}

// RegisterRoutes registers webhook routes.
func (h *Handler) RegisterRoutes(router *gin.RouterGroup) {
	router.POST("", h.CreateWebhook)
	router.GET("", h.ListWebhooks)
	router.GET("/:id", h.GetWebhook)
	router.PUT("/:id", h.UpdateWebhook)
	router.DELETE("/:id", h.DeleteWebhook)
}

// CreateWebhook handles webhook creation.
func (h *Handler) CreateWebhook(c *gin.Context) {
	var req CreateWebhookRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	webhook, err := h.manager.Create(req)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusCreated, webhook)
}

// ListWebhooks handles listing webhooks.
func (h *Handler) ListWebhooks(c *gin.Context) {
	webhooks, err := h.manager.store.List()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"webhooks": webhooks})
}

// GetWebhook handles getting a single webhook.
func (h *Handler) GetWebhook(c *gin.Context) {
	id := c.Param("id")
	webhook, err := h.manager.store.Get(id)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "webhook not found"})
		return
	}

	c.JSON(http.StatusOK, webhook)
}

// UpdateWebhookRequest represents a request to update a webhook.
type UpdateWebhookRequest struct {
	URL         string            `json:"url,omitempty"`
	Secret      string            `json:"secret,omitempty"`
	Events      []string          `json:"events,omitempty"`
	Headers     map[string]string `json:"headers,omitempty"`
	Active      *bool             `json:"active,omitempty"`
	RetryConfig *RetryConfig      `json:"retry_config,omitempty"`
}

// UpdateWebhook handles webhook updates.
func (h *Handler) UpdateWebhook(c *gin.Context) {
	id := c.Param("id")
	webhook, err := h.manager.store.Get(id)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "webhook not found"})
		return
	}

	var req UpdateWebhookRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.URL != "" {
		webhook.URL = req.URL
	}
	if req.Secret != "" {
		webhook.Secret = req.Secret
	}
	if len(req.Events) > 0 {
		webhook.Events = req.Events
	}
	if req.Headers != nil {
		webhook.Headers = req.Headers
	}
	if req.Active != nil {
		webhook.Active = *req.Active
	}
	if req.RetryConfig != nil {
		webhook.RetryConfig = *req.RetryConfig
	}

	webhook.UpdatedAt = time.Now()
	if err := h.manager.store.Update(webhook); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, webhook)
}

// DeleteWebhook handles webhook deletion.
func (h *Handler) DeleteWebhook(c *gin.Context) {
	id := c.Param("id")
	if err := h.manager.store.Delete(id); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.Status(http.StatusNoContent)
}

