// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-018: Audit Logging - Middleware for comprehensive audit logging
package middleware

import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
)

// AuditLevel represents the audit log level.
type AuditLevel int

const (
	// AuditLevelNone disables audit logging.
	AuditLevelNone AuditLevel = 0
	// AuditLevelBasic logs request/response metadata.
	AuditLevelBasic AuditLevel = 1
	// AuditLevelFull logs full request/response bodies.
	AuditLevelFull AuditLevel = 2
	// AuditLevelSensitive includes sensitive data (be careful!).
	AuditLevelSensitive AuditLevel = 3
)

// AuditEntry represents a single audit log entry.
type AuditEntry struct {
	ID           string            `json:"id"`
	Timestamp    time.Time         `json:"timestamp"`
	Level        AuditLevel        `json:"level"`
	Method       string            `json:"method"`
	Path         string            `json:"path"`
	StatusCode   int               `json:"status_code"`
	Duration     time.Duration     `json:"duration_ms"`
	ClientIP     string            `json:"client_ip"`
	UserAgent    string            `json:"user_agent"`
	RequestID    string            `json:"request_id,omitempty"`
	UserID       string            `json:"user_id,omitempty"`
	Namespace    string            `json:"namespace,omitempty"`
	Resource     string            `json:"resource,omitempty"`
	Action       string            `json:"action,omitempty"`
	RequestBody  json.RawMessage   `json:"request_body,omitempty"`
	ResponseSize int               `json:"response_size,omitempty"`
	ResponseBody json.RawMessage   `json:"response_body,omitempty"`
	Headers      map[string]string `json:"headers,omitempty"`
	QueryParams  map[string]string `json:"query_params,omitempty"`
	Success      bool              `json:"success"`
	Error        string            `json:"error,omitempty"`
	Metadata     map[string]string `json:"metadata,omitempty"`
}

// AuditSink defines the interface for audit log sinks.
type AuditSink interface {
	Write(entry *AuditEntry) error
	Close() error
}

// AuditConfig configures the audit logging middleware.
type AuditConfig struct {
	Level           AuditLevel
	RequestIDHeader string
	UserIDHeader    string
	ExcludePaths    []string
	RedactHeaders   []string
	SensitiveFields []string
	BufferSize      int
	FlushInterval   time.Duration
	Sinks           []AuditSink
}

// DefaultAuditConfig returns default audit configuration.
func DefaultAuditConfig() AuditConfig {
	return AuditConfig{
		Level:           AuditLevelBasic,
		RequestIDHeader: "X-Request-ID",
		UserIDHeader:    "X-User-ID",
		ExcludePaths:    []string{"/health", "/health/live", "/health/ready", "/metrics"},
		RedactHeaders: []string{
			"Authorization",
			"Cookie",
			"X-API-Key",
			"X-Webhook-Secret",
		},
		SensitiveFields: []string{
			"password",
			"secret",
			"token",
			"api_key",
			"private_key",
		},
		BufferSize:    1000,
		FlushInterval: 5 * time.Second,
		Sinks:         make([]AuditSink, 0),
	}
}

// AuditMiddleware provides audit logging.
type AuditMiddleware struct {
	config AuditConfig
	buffer chan *AuditEntry
	mu     sync.RWMutex
}

// NewAuditMiddleware creates a new audit middleware.
func NewAuditMiddleware(config AuditConfig) *AuditMiddleware {
	am := &AuditMiddleware{
		config: config,
		buffer: make(chan *AuditEntry, config.BufferSize),
	}

	// Start background flush
	if config.FlushInterval > 0 && len(config.Sinks) > 0 {
		go am.flushLoop()
	}

	return am
}

// shouldExclude checks if path should be excluded.
func (am *AuditMiddleware) shouldExclude(path string) bool {
	for _, exclude := range am.config.ExcludePaths {
		if strings.HasPrefix(path, exclude) {
			return true
		}
	}
	return false
}

// Middleware returns the Gin middleware function.
func (am *AuditMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Check if excluded
		if am.shouldExclude(c.Request.URL.Path) {
			c.Next()
			return
		}

		start := time.Now()

		// Capture request body if level is Full or higher
		var requestBody []byte
		if am.config.Level >= AuditLevelFull {
			if c.Request.Body != nil {
				requestBody, _ = c.GetRawData()
				c.Request.Body = strings.NewReader(string(requestBody))
			}
		}

		// Create audit entry
		entry := &AuditEntry{
			ID:          generateSpanID(), // Reuse span ID generator
			Timestamp:   start,
			Level:       am.config.Level,
			Method:      c.Request.Method,
			Path:        c.Request.URL.Path,
			ClientIP:    c.ClientIP(),
			UserAgent:   c.Request.UserAgent(),
			RequestID:   c.GetHeader(am.config.RequestIDHeader),
			UserID:      c.GetHeader(am.config.UserIDHeader),
			QueryParams: extractQueryParams(c),
			Headers:     am.redactHeaders(c.Request.Header),
			Metadata:    make(map[string]string),
		}

		// Add request body
		if am.config.Level >= AuditLevelFull && len(requestBody) > 0 {
			entry.RequestBody = am.sanitizeBody(requestBody)
		}

		// Process request
		c.Next()

		// Complete entry
		entry.Duration = time.Since(start)
		entry.StatusCode = c.Writer.Status()
		entry.Success = c.Writer.Status() < 400

		if !entry.Success {
			if len(c.Errors) > 0 {
				entry.Error = c.Errors.String()
			}
		}

		// Extract action from path
		entry.Action = extractAction(c)
		entry.Resource = extractResource(c)
		entry.Namespace = c.Param("namespace")

		// Capture response size
		entry.ResponseSize = c.Writer.Size()

		// Write to sinks
		am.writeEntry(entry)
	}
}

// extractQueryParams extracts query parameters.
func extractQueryParams(c *gin.Context) map[string]string {
	params := make(map[string]string)
	for key, values := range c.Request.URL.Query() {
		if len(values) > 0 {
			params[key] = values[0]
		}
	}
	return params
}

// extractAction extracts the action from the request.
func extractAction(c *gin.Context) string {
	switch c.Request.Method {
	case http.MethodGet:
		return "read"
	case http.MethodPost:
		return "create"
	case http.MethodPut, http.MethodPatch:
		return "update"
	case http.MethodDelete:
		return "delete"
	default:
		return strings.ToLower(c.Request.Method)
	}
}

// extractResource extracts the resource type from the path.
func extractResource(c *gin.Context) string {
	path := c.FullPath()
	if path == "" {
		path = c.Request.URL.Path
	}

	// Extract resource from path patterns
	// /v1/namespaces/:namespace/sandboxes -> sandboxes
	// /v1/sessions/:id -> sessions
	parts := strings.Split(path, "/")
	for i, part := range parts {
		if strings.HasPrefix(part, ":") && i > 0 {
			return parts[i-1]
		}
	}

	// Fallback: use last non-parameter segment
	for i := len(parts) - 1; i >= 0; i-- {
		if parts[i] != "" && !strings.HasPrefix(parts[i], ":") {
			return parts[i]
		}
	}

	return "unknown"
}

// redactHeaders redacts sensitive headers.
func (am *AuditMiddleware) redactHeaders(headers http.Header) map[string]string {
	result := make(map[string]string)
	for key, values := range headers {
		if len(values) > 0 {
			// Check if header should be redacted
			shouldRedact := false
			for _, redactKey := range am.config.RedactHeaders {
				if strings.EqualFold(key, redactKey) {
					shouldRedact = true
					break
				}
			}

			if shouldRedact {
				result[key] = "[REDACTED]"
			} else {
				result[key] = values[0]
			}
		}
	}
	return result
}

// sanitizeBody sanitizes request body by removing sensitive fields.
func (am *AuditMiddleware) sanitizeBody(body []byte) json.RawMessage {
	if len(body) == 0 {
		return nil
	}

	// Try to parse as JSON
	var data map[string]interface{}
	if err := json.Unmarshal(body, &data); err != nil {
		// Not JSON, return as-is (truncated)
		if len(body) > 10000 {
			return json.RawMessage(body[:10000])
		}
		return json.RawMessage(body)
	}

	// Remove sensitive fields
	for _, field := range am.config.SensitiveFields {
		if _, exists := data[field]; exists {
			data[field] = "[REDACTED]"
		}
	}

	// Marshal back
	sanitized, err := json.Marshal(data)
	if err != nil {
		return json.RawMessage(body[:min(len(body), 10000)])
	}

	return sanitized
}

// writeEntry writes an audit entry to sinks.
func (am *AuditMiddleware) writeEntry(entry *AuditEntry) {
	// Try to buffer first
	select {
	case am.buffer <- entry:
		// Buffered successfully
		return
	default:
		// Buffer full, write directly
	}

	// Write directly to sinks
	am.flushEntry(entry)
}

// flushLoop periodically flushes the buffer.
func (am *AuditMiddleware) flushLoop() {
	ticker := time.NewTicker(am.config.FlushInterval)
	defer ticker.Stop()

	for {
		select {
		case entry := <-am.buffer:
			am.flushEntry(entry)
		case <-ticker.C:
			// Flush any remaining
			for {
				select {
				case entry := <-am.buffer:
					am.flushEntry(entry)
				default:
					goto done
				}
			}
		done:
		}
	}
}

// flushEntry flushes a single entry to all sinks.
func (am *AuditMiddleware) flushEntry(entry *AuditEntry) {
	for _, sink := range am.config.Sinks {
		if err := sink.Write(entry); err != nil {
			// Log error but continue with other sinks
			fmt.Printf("audit sink error: %v\n", err)
		}
	}
}

// Close closes the audit middleware.
func (am *AuditMiddleware) Close() error {
	// Flush remaining entries
	close(am.buffer)
	for entry := range am.buffer {
		am.flushEntry(entry)
	}

	// Close sinks
	for _, sink := range am.config.Sinks {
		sink.Close()
	}

	return nil
}

// ConsoleSink writes audit logs to console.
type ConsoleSink struct {
	encoder *json.Encoder
}

// NewConsoleSink creates a new console sink.
func NewConsoleSink() *ConsoleSink {
	return &ConsoleSink{
		encoder: json.NewEncoder(nil),
	}
}

// Write writes an audit entry.
func (cs *ConsoleSink) Write(entry *AuditEntry) error {
	output, err := json.Marshal(entry)
	if err != nil {
		return err
	}
	fmt.Println(string(output))
	return nil
}

// Close closes the sink.
func (cs *ConsoleSink) Close() error {
	return nil
}

// MemorySink stores audit logs in memory for testing.
type MemorySink struct {
	mu      sync.RWMutex
	entries []*AuditEntry
}

// NewMemorySink creates a new memory sink.
func NewMemorySink() *MemorySink {
	return &MemorySink{
		entries: make([]*AuditEntry, 0),
	}
}

// Write writes an audit entry.
func (ms *MemorySink) Write(entry *AuditEntry) error {
	ms.mu.Lock()
	defer ms.mu.Unlock()
	ms.entries = append(ms.entries, entry)
	return nil
}

// GetEntries returns all stored entries.
func (ms *MemorySink) GetEntries() []*AuditEntry {
	ms.mu.RLock()
	defer ms.mu.RUnlock()
	return append([]*AuditEntry(nil), ms.entries...)
}

// Clear clears all entries.
func (ms *MemorySink) Clear() {
	ms.mu.Lock()
	defer ms.mu.Unlock()
	ms.entries = make([]*AuditEntry, 0)
}

// Close closes the sink.
func (ms *MemorySink) Close() error {
	return nil
}

// min returns the minimum of two integers.
func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

// Package multiregion provides multi-region support for AgentCube.
// AR-019: Multi-Region Support - Configuration-driven
package multiregion

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"time"
)

// Region represents a geographic region.
type Region struct {
	ID              string            `json:"id"`
	Name            string            `json:"name"`
	Location        string            `json:"location"`
	Endpoint        string            `json:"endpoint"`
	Priority        int               `json:"priority"`
	Active          bool              `json:"active"`
	Weight          int               `json:"weight"`
	Metadata        map[string]string `json:"metadata,omitempty"`
	LastHealthCheck time.Time         `json:"last_health_check,omitempty"`
	Healthy         bool              `json:"healthy"`
}

// RegionConfig configures multi-region support.
type RegionConfig struct {
	CurrentRegion   string
	Regions         []Region
	HealthCheckInterval time.Duration
	FailoverEnabled bool
	GeoRouting      bool
}

// DefaultRegionConfig returns default region configuration.
func DefaultRegionConfig() RegionConfig {
	return RegionConfig{
		CurrentRegion:   "default",
		HealthCheckInterval: 30 * time.Second,
		FailoverEnabled: true,
		GeoRouting:      true,
		Regions: []Region{
			{
				ID:       "default",
				Name:     "Default",
				Location: "us-east-1",
				Endpoint: "https://api.agentcube.local",
				Priority: 1,
				Active:   true,
				Weight:   100,
				Healthy:  true,
			},
		},
	}
}

// Manager manages multi-region configuration.
type Manager struct {
	config  RegionConfig
	regions map[string]*Region
	mu      sync.RWMutex
}

// NewManager creates a new region manager.
func NewManager(config RegionConfig) *Manager {
	m := &Manager{
		config:  config,
		regions: make(map[string]*Region),
	}

	for _, region := range config.Regions {
		m.regions[region.ID] = &region
	}

	// Start health check loop if enabled
	if config.HealthCheckInterval > 0 {
		go m.healthCheckLoop()
	}

	return m
}

// GetRegion gets a region by ID.
func (m *Manager) GetRegion(id string) (*Region, bool) {
	m.mu.RLock()
	defer m.mu.RUnlock()
	region, exists := m.regions[id]
	return region, exists
}

// GetCurrentRegion returns the current region.
func (m *Manager) GetCurrentRegion() *Region {
	region, _ := m.GetRegion(m.config.CurrentRegion)
	return region
}

// ListRegions returns all regions.
func (m *Manager) ListRegions() []Region {
	m.mu.RLock()
	defer m.mu.RUnlock()

	regions := make([]Region, 0, len(m.regions))
	for _, region := range m.regions {
		regions = append(regions, *region)
	}
	return regions
}

// ListActiveRegions returns active regions.
func (m *Manager) ListActiveRegions() []Region {
	m.mu.RLock()
	defer m.mu.RUnlock()

	regions := make([]Region, 0)
	for _, region := range m.regions {
		if region.Active {
			regions = append(regions, *region)
		}
	}
	return regions
}

// ListHealthyRegions returns healthy regions.
func (m *Manager) ListHealthyRegions() []Region {
	m.mu.RLock()
	defer m.mu.RUnlock()

	regions := make([]Region, 0)
	for _, region := range m.regions {
		if region.Active && region.Healthy {
			regions = append(regions, *region)
		}
	}
	return regions
}

// SelectRegion selects the best region for a request.
func (m *Manager) SelectRegion(preferredRegion string) (*Region, error) {
	// Check preferred region first
	if preferredRegion != "" {
		region, exists := m.GetRegion(preferredRegion)
		if exists && region.Active && region.Healthy {
			return region, nil
		}
	}

	// Use geo-routing if enabled
	if m.config.GeoRouting {
		return m.selectByGeo(), nil
	}

	// Fall back to priority-based selection
	return m.selectByPriority(), nil
}

// selectByGeo selects region based on geography (placeholder).
func (m *Manager) selectByGeo() *Region {
	// In real implementation, this would use client IP for geo-location
	// For now, return the current region
	return m.GetCurrentRegion()
}

// selectByPriority selects region by priority.
func (m *Manager) selectByPriority() *Region {
	m.mu.RLock()
	defer m.mu.RUnlock()

	var selected *Region
	for _, region := range m.regions {
		if !region.Active || !region.Healthy {
			continue
		}
		if selected == nil || region.Priority < selected.Priority {
			selected = region
		}
	}

	if selected == nil {
		return m.GetCurrentRegion()
	}
	return selected
}

// healthCheckLoop performs periodic health checks.
func (m *Manager) healthCheckLoop() {
	ticker := time.NewTicker(m.config.HealthCheckInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			m.checkAllRegions()
		}
	}
}

// checkAllRegions checks health of all regions.
func (m *Manager) checkAllRegions() {
	for _, region := range m.regions {
		m.checkRegion(region)
	}
}

// checkRegion checks health of a single region.
func (m *Manager) checkRegion(region *Region) {
	// In real implementation, this would make HTTP health check
	// For now, assume healthy
	region.LastHealthCheck = time.Now()
}

// UpdateRegion updates a region.
func (m *Manager) UpdateRegion(region *Region) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, exists := m.regions[region.ID]; !exists {
		return errors.New("region not found")
	}

	m.regions[region.ID] = region
	return nil
}

// AddRegion adds a new region.
func (m *Manager) AddRegion(region Region) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, exists := m.regions[region.ID]; exists {
		return errors.New("region already exists")
	}

	m.regions[region.ID] = &region
	return nil
}

// RemoveRegion removes a region.
func (m *Manager) RemoveRegion(id string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if id == m.config.CurrentRegion {
		return errors.New("cannot remove current region")
	}

	delete(m.regions, id)
	return nil
}

// FailoverRegion performs failover to a healthy region.
func (m *Manager) FailoverRegion(failedRegionID string) (*Region, error) {
	if !m.config.FailoverEnabled {
		return nil, errors.New("failover not enabled")
	}

	failedRegion, exists := m.GetRegion(failedRegionID)
	if !exists {
		return nil, errors.New("region not found")
	}

	// Mark as unhealthy
	failedRegion.Healthy = false
	failedRegion.Active = false

	// Select new region
	newRegion := m.selectByPriority()
	if newRegion == nil || newRegion.ID == failedRegionID {
		return nil, errors.New("no healthy region available for failover")
	}

	return newRegion, nil
}

// ReplicationManager manages cross-region replication.
type ReplicationManager struct {
	regionManager *Manager
}

// NewReplicationManager creates a new replication manager.
func NewReplicationManager(regionManager *Manager) *ReplicationManager {
	return &ReplicationManager{
		regionManager: regionManager,
	}
}

// ReplicateSession replicates session to other regions.
func (rm *ReplicationManager) ReplicateSession(ctx context.Context, sessionID string, regions []string) error {
	// Placeholder implementation
	return nil
}

// SyncRegion syncs data to a specific region.
func (rm *ReplicationManager) SyncRegion(ctx context.Context, regionID string) error {
	region, exists := rm.regionManager.GetRegion(regionID)
	if !exists {
		return fmt.Errorf("region %s not found", regionID)
	}

	if !region.Active {
		return fmt.Errorf("region %s is not active", regionID)
	}

	// Placeholder implementation
	return nil
}

