// Package scheduling provides advanced scheduling for AgentCube.
// AR-020: Advanced Scheduling - Kubernetes native scheduling
package scheduling

import (
	"context"
	"fmt"
	"math/rand"
	"sort"
	"sync"
	"time"
)

// SchedulePolicy defines the scheduling policy.
type SchedulePolicy int

const (
	// PolicyRoundRobin uses round-robin scheduling.
	PolicyRoundRobin SchedulePolicy = 0
	// PolicyLeastLoad schedules on least loaded node.
	PolicyLeastLoad SchedulePolicy = 1
	// PolicyAffinity schedules based on affinity rules.
	PolicyAffinity SchedulePolicy = 2
	// PolicyAntiAffinity schedules based on anti-affinity rules.
	PolicyAntiAffinity SchedulePolicy = 3
	// PolicyCostOptimized schedules for cost optimization.
	PolicyCostOptimized SchedulePolicy = 4
)

// Node represents a Kubernetes node.
type Node struct {
	ID            string            `json:"id"`
	Name          string            `json:"name"`
	Labels        map[string]string `json:"labels,omitempty"`
	Annotations   map[string]string `json:"annotations,omitempty"`
	Capacity      Resources         `json:"capacity"`
	Allocatable   Resources         `json:"allocatable"`
	Allocated     Resources         `json:"allocated"`
	Ready         bool              `json:"ready"`
	Unschedulable bool              `json:"unschedulable"`
	Score         int               `json:"score,omitempty"`
	LastUsed      time.Time         `json:"last_used,omitempty"`
}

// Resources represents compute resources.
type Resources struct {
	CPU     int64 `json:"cpu"`     // millicores
	Memory  int64 `json:"memory"`  // bytes
	Storage int64 `json:"storage"` // bytes
	GPU     int64 `json:"gpu"`     // count
}

// PodSpec represents a pod specification.
type PodSpec struct {
	Namespace    string            `json:"namespace"`
	Name         string            `json:"name"`
	Resources    Resources         `json:"resources"`
	Labels       map[string]string `json:"labels,omitempty"`
	NodeSelector map[string]string `json:"node_selector,omitempty"`
	Affinity     *Affinity         `json:"affinity,omitempty"`
	Tolerations  []Toleration      `json:"tolerations,omitempty"`
	Priority     int               `json:"priority,omitempty"`
}

// Affinity represents pod/node affinity rules.
type Affinity struct {
	NodeAffinity    *NodeAffinity    `json:"node_affinity,omitempty"`
	PodAffinity     *PodAffinity     `json:"pod_affinity,omitempty"`
	PodAntiAffinity *PodAntiAffinity `json:"pod_anti_affinity,omitempty"`
}

// NodeAffinity defines node affinity rules.
type NodeAffinity struct {
	Required  *NodeSelector   `json:"required,omitempty"`
	Preferred []PreferredNode `json:"preferred,omitempty"`
}

// NodeSelector defines required node selection.
type NodeSelector struct {
	Terms []NodeSelectorTerm `json:"terms"`
}

// NodeSelectorTerm defines a selector term.
type NodeSelectorTerm struct {
	MatchLabels      map[string]string   `json:"match_labels,omitempty"`
	MatchExpressions []SelectorExpression `json:"match_expressions,omitempty"`
}

// SelectorExpression defines a selector expression.
type SelectorExpression struct {
	Key      string   `json:"key"`
	Operator string   `json:"operator"`
	Values   []string `json:"values,omitempty"`
}

// PreferredNode defines a preferred node with weight.
