// Package cost provides cost optimization for AgentCube.
// AR-022: Cost Optimization - Analytics-driven
package cost

import (
	"context"
	"encoding/json"
	"fmt"
	"sort"
	"sync"
	"time"
)

// CostType represents types of costs.
type CostType string

const (
	// CostTypeCompute represents compute costs.
	CostTypeCompute CostType = "compute"
	// CostTypeStorage represents storage costs.
	CostTypeStorage CostType = "storage"
	// CostTypeNetwork represents network costs.
	CostTypeNetwork CostType = "network"
	// CostTypeLicense represents license costs.
	CostTypeLicense CostType = "license"
)

// CostRecord represents a cost record.
type CostRecord struct {
	ID           string            `json:"id"`
	Timestamp    time.Time         `json:"timestamp"`
	Type         CostType          `json:"type"`
	Resource     string            `json:"resource"`
	Amount       float64           `json:"amount"`
	Currency     string            `json:"currency"`
	Namespace    string            `json:"namespace,omitempty"`
	Labels       map[string]string `json:"labels,omitempty"`
	Region       string            `json:"region"`
	UnitPrice    float64           `json:"unit_price"`
	Quantity     float64           `json:"quantity"`
	Unit         string            `json:"unit"`
}

// CostConfig configures cost optimization.
type CostConfig struct {
	Budget          float64
	BudgetPeriod    time.Duration
	AlertThreshold  float64
	Currency        string
	OptimizationLevel int // 0=none, 1=conservative, 2=aggressive
}

// DefaultCostConfig returns default cost configuration.
func DefaultCostConfig() CostConfig {
	return CostConfig{
		BudgetPeriod:      30 * 24 * time.Hour,
		AlertThreshold:    0.8, // 80% of budget
		Currency:          "USD",
		OptimizationLevel: 1,
	}
}

// Optimizer provides cost optimization.
type Optimizer struct {
	config  CostConfig
	records []*CostRecord
	mu      sync.RWMutex
}

// NewOptimizer creates a new cost optimizer.
func NewOptimizer(config CostConfig) *Optimizer {
	return &Optimizer{
		config:  config,
		records: make([]*CostRecord, 0),
	}
}

// RecordCost records a cost.
func (o *Optimizer) RecordCost(record *CostRecord) {
	o.mu.Lock()
	defer o.mu.Unlock()

	if record.ID == "" {
		record.ID = generateCostID()
	}
	if record.Timestamp.IsZero() {
		record.Timestamp = time.Now()
	}
	if record.Currency == "" {
		record.Currency = o.config.Currency
	}

	o.records = append(o.records, record)
}

// GetTotalCost returns total cost for a period.
func (o *Optimizer) GetTotalCost(start, end time.Time, costType ...CostType) float64 {
	o.mu.RLock()
	defer o.mu.RUnlock()

	var total float64
	for _, record := range o.records {
		if record.Timestamp.Before(start) || record.Timestamp.After(end) {
			continue
		}

		if len(costType) > 0 {
			match := false
			for _, ct := range costType {
				if record.Type == ct {
					match = true
					break
				}
			}
			if !match {
				continue
			}
		}

		total += record.Amount
	}

	return total
}

// GetCurrentPeriodCost returns cost for the current budget period.
func (o *Optimizer) GetCurrentPeriodCost() float64 {
	now := time.Now()
	start := now.Add(-o.config.BudgetPeriod)
	return o.GetTotalCost(start, now)
}

// IsOverBudget checks if spending is over budget.
func (o *Optimizer) IsOverBudget() bool {
	if o.config.Budget <= 0 {
		return false
	}
	return o.GetCurrentPeriodCost() > o.config.Budget
}

// IsAlertThresholdReached checks if alert threshold is reached.
func (o *Optimizer) IsAlertThresholdReached() bool {
	if o.config.Budget <= 0 {
		return false
	}
	threshold := o.config.Budget * o.config.AlertThreshold
	return o.GetCurrentPeriodCost() > threshold
}

// GetCostByNamespace returns costs grouped by namespace.
func (o *Optimizer) GetCostByNamespace(start, end time.Time) map[string]float64 {
	o.mu.RLock()
	defer o.mu.RUnlock()

	costs := make(map[string]float64)
	for _, record := range o.records {
		if record.Timestamp.Before(start) || record.Timestamp.After(end) {
			continue
		}
		costs[record.Namespace] += record.Amount
	}

	return costs
}

// GetCostByResource returns costs grouped by resource.
func (o *Optimizer) GetCostByResource(start, end time.Time) map[string]float64 {
	o.mu.RLock()
	defer o.mu.RUnlock()

	costs := make(map[string]float64)
	for _, record := range o.records {
		if record.Timestamp.Before(start) || record.Timestamp.After(end) {
			continue
		}
		costs[record.Resource] += record.Amount
	}

	return costs
}

// GetTopCostlyResources returns the top N costly resources.
func (o *Optimizer) GetTopCostlyResources(start, end time.Time, n int) []ResourceCost {
	costs := o.GetCostByResource(start, end)

	var resources []ResourceCost
	for name, cost := range costs {
		resources = append(resources, ResourceCost{
			Name: name,
			Cost: cost,
		})
	}

	// Sort by cost (descending)
	sort.Slice(resources, func(i, j int) bool {
		return resources[i].Cost > resources[j].Cost
	})

	if len(resources) > n {
		resources = resources[:n]
	}

	return resources
}

// ResourceCost represents a resource and its cost.
type ResourceCost struct {
	Name string  `json:"name"`
	Cost float64 `json:"cost"`
}

// OptimizationRecommendation represents a cost optimization recommendation.
type OptimizationRecommendation struct {
	ID          string    `json:"id"`
	Timestamp   time.Time `json:"timestamp"`
	Type        string    `json:"type"`
	Resource    string    `json:"resource"`
	Description string    `json:"description"`
	PotentialSavings float64 `json:"potential_savings"`
	Confidence  float64   `json:"confidence"`
	Priority    int       `json:"priority"`
}

// GenerateRecommendations generates cost optimization recommendations.
func (o *Optimizer) GenerateRecommendations() []*OptimizationRecommendation {
	if o.config.OptimizationLevel == 0 {
		return nil
	}

	now := time.Now()
	start := now.Add(-7 * 24 * time.Hour)

	var recommendations []*OptimizationRecommendation

	// Check for idle resources
	recommendations = append(recommendations, o.checkIdleResources(start, now)...)

	// Check for over-provisioned resources
	recommendations = append(recommendations, o.checkOverProvisioned(start, now)...)

	// Check for spot/preemptible opportunities
	recommendations = append(recommendations, o.checkSpotOpportunities(start, now)...)

	// Sort by priority and potential savings
	sort.Slice(recommendations, func(i, j int) bool {
		scoreI := recommendations[i].PotentialSavings * recommendations[i].Confidence / float64(recommendations[i].Priority)
		scoreJ := recommendations[j].PotentialSavings * recommendations[j].Confidence / float64(recommendations[j].Priority)
		return scoreI > scoreJ
	})

	return recommendations
}

