// CostReport represents a cost report.
type CostReport struct {
	Period          string             `json:"period"`
	TotalCost       float64            `json:"total_cost"`
	Budget          float64            `json:"budget"`
	BudgetUtilization float64          `json:"budget_utilization"`
	ByType          map[string]float64 `json:"by_type"`
	ByNamespace     map[string]float64 `json:"by_namespace"`
	TopResources    []ResourceCost     `json:"top_resources"`
	Trends          []CostTrend        `json:"trends"`
}

// CostTrend represents a cost trend.
type CostTrend struct {
	Date time.Time `json:"date"`
	Cost float64   `json:"cost"`
}

// GenerateReport generates a cost report.
func (o *Optimizer) GenerateReport(period time.Duration) *CostReport {
	now := time.Now()
	start := now.Add(-period)

	totalCost := o.GetTotalCost(start, now)

	report := &CostReport{
		Period:          period.String(),
		TotalCost:       totalCost,
		Budget:          o.config.Budget,
		BudgetUtilization: 0,
		ByType:          o.getCostByType(start, now),
		ByNamespace:     o.GetCostByNamespace(start, now),
		TopResources:    o.GetTopCostlyResources(start, now, 10),
	}

	if o.config.Budget > 0 {
		report.BudgetUtilization = totalCost / o.config.Budget
	}

	return report
}

// getCostByType returns costs grouped by type.
func (o *Optimizer) getCostByType(start, end time.Time) map[string]float64 {
	o.mu.RLock()
	defer o.mu.RUnlock()

	costs := make(map[string]float64)
	for _, record := range o.records {
		if record.Timestamp.Before(start) || record.Timestamp.After(end) {
			continue
		}
		costs[string(record.Type)] += record.Amount
	}

	return costs
}

// BudgetManager manages budgets.
type BudgetManager struct {
	optimizer *Optimizer
	alerts    []BudgetAlert
	mu        sync.RWMutex
}

// BudgetAlert represents a budget alert.
type BudgetAlert struct {
	ID        string    `json:"id"`
	Timestamp time.Time `json:"timestamp"`
	Type      string    `json:"type"`
	Message   string    `json:"message"`
	Severity  string    `json:"severity"`
}

// NewBudgetManager creates a new budget manager.
func NewBudgetManager(optimizer *Optimizer) *BudgetManager {
	return &BudgetManager{
		optimizer: optimizer,
		alerts:    make([]BudgetAlert, 0),
	}
}

// CheckBudget checks the budget and generates alerts.
func (bm *BudgetManager) CheckBudget() []*BudgetAlert {
	var alerts []*BudgetAlert

	if bm.optimizer.IsOverBudget() {
		alerts = append(alerts, &BudgetAlert{
			ID:        generateCostID(),
			Timestamp: time.Now(),
			Type:      "budget_exceeded",
			Message:   fmt.Sprintf("Budget exceeded: spent %.2f, budget %.2f", bm.optimizer.GetCurrentPeriodCost(), bm.optimizer.config.Budget),
			Severity:  "critical",
		})
	} else if bm.optimizer.IsAlertThresholdReached() {
		alerts = append(alerts, &BudgetAlert{
			ID:        generateCostID(),
			Timestamp: time.Now(),
			Type:      "budget_threshold",
			Message:   fmt.Sprintf("Budget threshold reached: spent %.2f (%.0f%%)", bm.optimizer.GetCurrentPeriodCost(), bm.optimizer.config.AlertThreshold*100),
			Severity:  "warning",
		})
	}

	// Store alerts
	bm.mu.Lock()
	for _, alert := range alerts {
		bm.alerts = append(bm.alerts, *alert)
	}
	bm.mu.Unlock()

	return alerts
}

// GetAlerts returns all alerts.
func (bm *BudgetManager) GetAlerts() []BudgetAlert {
	bm.mu.RLock()
	defer bm.mu.RUnlock()
	return append([]BudgetAlert(nil), bm.alerts...)
}

