package middleware

import (
	"errors"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
)

func TestCircuitBreakerState_String(t *testing.T) {
	assert.Equal(t, "closed", StateClosed.String())
	assert.Equal(t, "open", StateOpen.String())
	assert.Equal(t, "half-open", StateHalfOpen.String())
	assert.Equal(t, "unknown", CircuitBreakerState(99).String())
}

func TestDefaultCircuitBreakerConfig(t *testing.T) {
	config := DefaultCircuitBreakerConfig("test")
	assert.Equal(t, "test", config.Name)
	assert.Equal(t, uint32(5), config.MaxFailures)
	assert.Equal(t, 30*time.Second, config.Timeout)
	assert.Equal(t, uint32(3), config.MaxRequests)
	assert.NotNil(t, config.ReadyToTrip)
	assert.NotNil(t, config.IsSuccessful)
}

func TestCircuitBreaker_Call_Success(t *testing.T) {
	cb := NewCircuitBreaker(DefaultCircuitBreakerConfig("test"))

	err := cb.Call(func() error {
		return nil
	})

	assert.NoError(t, err)
	assert.Equal(t, StateClosed, cb.State())
}

func TestCircuitBreaker_Call_Failure(t *testing.T) {
	cb := NewCircuitBreaker(DefaultCircuitBreakerConfig("test"))

	testErr := errors.New("test error")
	err := cb.Call(func() error {
		return testErr
	})

	assert.Equal(t, testErr, err)
	assert.Equal(t, StateClosed, cb.State())
}

func TestCircuitBreaker_OpenCircuit(t *testing.T) {
	config := CircuitBreakerConfig{
		Name:        "test",
		MaxFailures: 2,
		Timeout:     1 * time.Second,
		MaxRequests: 1,
		ReadyToTrip: func(count uint32) bool { return count >= 2 },
		IsSuccessful: func(err error) bool { return err == nil },
	}

	cb := NewCircuitBreaker(config)

	// Trigger failures to open circuit
	for i := 0; i < 3; i++ {
		cb.Call(func() error {
			return errors.New("failure")
		})
	}

	assert.Equal(t, StateOpen, cb.State())

	// Subsequent calls should fail with circuit open
	err := cb.Call(func() error {
		return nil
	})

	assert.Equal(t, ErrCircuitBreakerOpen, err)
}

func TestCircuitBreaker_HalfOpen(t *testing.T) {
	config := CircuitBreakerConfig{
		Name:        "test",
		MaxFailures: 1,
		Timeout:     100 * time.Millisecond,
		MaxRequests: 1,
		ReadyToTrip: func(count uint32) bool { return count >= 1 },
		IsSuccessful: func(err error) bool { return err == nil },
	}

	cb := NewCircuitBreaker(config)

	// Open the circuit
	cb.Call(func() error {
		return errors.New("failure")
	})

	assert.Equal(t, StateOpen, cb.State())

	// Wait for timeout
	time.Sleep(150 * time.Millisecond)

	// Circuit should be half-open
	assert.Equal(t, StateHalfOpen, cb.State())

	// One request should be allowed in half-open
	err := cb.Call(func() error {
		return nil
	})
	assert.NoError(t, err)

	// Circuit should be closed again
	assert.Equal(t, StateClosed, cb.State())
}

func TestCircuitBreaker_Counts(t *testing.T) {
	c := Counts{}

	c.OnSuccess()
	assert.Equal(t, uint32(1), c.Requests)
	assert.Equal(t, uint32(1), c.TotalSuccesses)
	assert.Equal(t, uint32(0), c.TotalFailures)
	assert.Equal(t, uint32(1), c.ConsecutiveSuccesses)
	assert.Equal(t, uint32(0), c.ConsecutiveFailures)

	c.OnFailure()
	assert.Equal(t, uint32(2), c.Requests)
	assert.Equal(t, uint32(1), c.TotalSuccesses)
	assert.Equal(t, uint32(1), c.TotalFailures)
	assert.Equal(t, uint32(0), c.ConsecutiveSuccesses)
	assert.Equal(t, uint32(1), c.ConsecutiveFailures)
}

func TestCircuitBreakerMiddleware_Middleware(t *testing.T) {
	config := DefaultCircuitBreakerConfig("test")
	cbm := NewCircuitBreakerMiddleware(config)

	router := setupValidationTest()
	router.Use(cbm.Middleware())
	router.GET("/test", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"status": "ok"})
	})

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/test", nil)
	router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)
}

func TestCircuitBreakerMiddleware_Middleware_Error(t *testing.T) {
	config := CircuitBreakerConfig{
		Name:        "test",
		MaxFailures: 1,
		Timeout:     1 * time.Second,
		MaxRequests: 1,
		ReadyToTrip: func(count uint32) bool { return count >= 1 },
	}

	cbm := NewCircuitBreakerMiddleware(config)

	router := setupValidationTest()
	router.Use(cbm.Middleware())
	router.GET("/test", func(c *gin.Context) {
		c.Error(errors.New("test error"))
		c.Status(http.StatusInternalServerError)
	})

	// First request should work but record failure
	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/test", nil)
	router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusInternalServerError, w.Code)
}

func TestCircuitBreakerManager(t *testing.T) {
	manager := NewCircuitBreakerManager()

	config := DefaultCircuitBreakerConfig("cb1")
	cb1 := manager.GetOrCreate("cb1", config)
	assert.NotNil(t, cb1)

	// Get same circuit breaker
	cb1Again := manager.GetOrCreate("cb1", config)
	assert.Equal(t, cb1, cb1Again)

	// Get different circuit breaker
	cb2 := manager.GetOrCreate("cb2", config)
	assert.NotEqual(t, cb1, cb2)

	// Check existence
	cb, exists := manager.Get("cb1")
	assert.True(t, exists)
	assert.Equal(t, cb1, cb)

	_, exists = manager.Get("nonexistent")
	assert.False(t, exists)

	// List all
	names := manager.List()
	assert.Len(t, names, 2)

	// Remove
	manager.Remove("cb1")
	_, exists = manager.Get("cb1")
	assert.False(t, exists)
}

