// Package scheduling provides advanced scheduling for AgentCube.
// AR-020: Advanced Scheduling - Kubernetes native scheduling
package scheduling

import (
	"context"
	"fmt"
	"math/rand"
	"sort"
	"sync"
	"time"
)

// SchedulePolicy defines the scheduling policy.
type SchedulePolicy int

const (
	// PolicyRoundRobin uses round-robin scheduling.
	PolicyRoundRobin SchedulePolicy = 0
	// PolicyLeastLoad schedules on least loaded node.
	PolicyLeastLoad SchedulePolicy = 1
	// PolicyAffinity schedules based on affinity rules.
	PolicyAffinity SchedulePolicy = 2
	// PolicyAntiAffinity schedules based on anti-affinity rules.
	PolicyAntiAffinity SchedulePolicy = 3
	// PolicyCostOptimized schedules for cost optimization.
	PolicyCostOptimized SchedulePolicy = 4
)

// Node represents a Kubernetes node.
type Node struct {
	ID            string            `json:"id"`
	Name          string            `json:"name"`
	Labels        map[string]string `json:"labels,omitempty"`
	Annotations   map[string]string `json:"annotations,omitempty"`
	Capacity      Resources         `json:"capacity"`
	Allocatable   Resources         `json:"allocatable"`
	Allocated     Resources         `json:"allocated"`
	Ready         bool              `json:"ready"`
	Unschedulable bool              `json:"unschedulable"`
	Score         int               `json:"score,omitempty"`
	LastUsed      time.Time         `json:"last_used,omitempty"`
}

// Resources represents compute resources.
type Resources struct {
	CPU     int64 `json:"cpu"`     // millicores
	Memory  int64 `json:"memory"`  // bytes
	Storage int64 `json:"storage"` // bytes
	GPU     int64 `json:"gpu"`     // count
}

// PodSpec represents a pod specification.
type PodSpec struct {
	Namespace    string            `json:"namespace"`
	Name         string            `json:"name"`
	Resources    Resources         `json:"resources"`
	Labels       map[string]string `json:"labels,omitempty"`
	NodeSelector map[string]string `json:"node_selector,omitempty"`
	Affinity     *Affinity         `json:"affinity,omitempty"`
	Tolerations  []Toleration      `json:"tolerations,omitempty"`
	Priority     int               `json:"priority,omitempty"`
}

// Affinity represents pod/node affinity rules.
type Affinity struct {
	NodeAffinity    *NodeAffinity    `json:"node_affinity,omitempty"`
	PodAffinity     *PodAffinity     `json:"pod_affinity,omitempty"`
	PodAntiAffinity *PodAntiAffinity `json:"pod_anti_affinity,omitempty"`
}

// NodeAffinity defines node affinity rules.
type NodeAffinity struct {
	Required  *NodeSelector   `json:"required,omitempty"`
	Preferred []PreferredNode `json:"preferred,omitempty"`
}

// NodeSelector defines required node selection.
type NodeSelector struct {
	Terms []NodeSelectorTerm `json:"terms"`
}

// NodeSelectorTerm defines a selector term.
type NodeSelectorTerm struct {
	MatchLabels      map[string]string    `json:"match_labels,omitempty"`
	MatchExpressions []SelectorExpression `json:"match_expressions,omitempty"`
}

// SelectorExpression defines a selector expression.
type SelectorExpression struct {
	Key      string   `json:"key"`
	Operator string   `json:"operator"`
	Values   []string `json:"values,omitempty"`
}

// PreferredNode defines a preferred node with weight.
type PreferredNode struct {
	Weight int              `json:"weight"`
	Term   NodeSelectorTerm `json:"term"`
}

// PodAffinity defines pod affinity rules.
type PodAffinity struct {
	Required  []PodAffinityTerm     `json:"required,omitempty"`
	Preferred []WeightedPodAffinity `json:"preferred,omitempty"`
}

// PodAntiAffinity defines pod anti-affinity rules.
type PodAntiAffinity struct {
	Required  []PodAffinityTerm     `json:"required,omitempty"`
	Preferred []WeightedPodAffinity `json:"preferred,omitempty"`
}

// PodAffinityTerm defines a pod affinity term.
type PodAffinityTerm struct {
	LabelSelector *LabelSelector `json:"label_selector,omitempty"`
	Namespaces    []string       `json:"namespaces,omitempty"`
	TopologyKey   string         `json:"topology_key"`
}

// WeightedPodAffinity defines weighted pod affinity.
type WeightedPodAffinity struct {
	Weight int             `json:"weight"`
	Term   PodAffinityTerm `json:"term"`
}

// LabelSelector defines a label selector.
type LabelSelector struct {
	MatchLabels      map[string]string    `json:"match_labels,omitempty"`
	MatchExpressions []SelectorExpression `json:"match_expressions,omitempty"`
}

// Toleration defines a pod toleration.
type Toleration struct {
	Key      string `json:"key"`
	Operator string `json:"operator"`
	Value    string `json:"value,omitempty"`
	Effect   string `json:"effect,omitempty"`
}

// ScheduleResult represents the result of scheduling.
type ScheduleResult struct {
	NodeID    string    `json:"node_id"`
	NodeName  string    `json:"node_name"`
	Score     int       `json:"score"`
	Reason    string    `json:"reason,omitempty"`
	Timestamp time.Time `json:"timestamp"`
}

// Scheduler schedules pods to nodes.
type Scheduler struct {
	policy     SchedulePolicy
	nodes      map[string]*Node
	roundRobin int
	mu         sync.RWMutex
}

// NewScheduler creates a new scheduler.
func NewScheduler(policy SchedulePolicy) *Scheduler {
	return &Scheduler{
		policy:     policy,
		nodes:      make(map[string]*Node),
		roundRobin: 0,
	}
}

// RegisterNode registers a node with the scheduler.
func (s *Scheduler) RegisterNode(node *Node) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.nodes[node.ID] = node
}

// UnregisterNode unregisters a node.
func (s *Scheduler) UnregisterNode(nodeID string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	delete(s.nodes, nodeID)
}

// UpdateNode updates a node.
func (s *Scheduler) UpdateNode(node *Node) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.nodes[node.ID] = node
}

// Schedule schedules a pod to a node.
func (s *Scheduler) Schedule(ctx context.Context, pod *PodSpec) (*ScheduleResult, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	// Get available nodes
	candidates := s.filterNodes(pod)
	if len(candidates) == 0 {
		return nil, fmt.Errorf("no suitable nodes found for pod %s/%s", pod.Namespace, pod.Name)
	}

	// Score nodes
	scored := s.scoreNodes(candidates, pod)

	// Select node based on policy
	var selected *Node
	switch s.policy {
	case PolicyRoundRobin:
		selected = s.selectRoundRobin(scored)
	case PolicyLeastLoad:
		selected = s.selectLeastLoad(scored)
	case PolicyAffinity:
		selected = s.selectByAffinity(scored, pod)
	case PolicyAntiAffinity:
		selected = s.selectByAntiAffinity(scored, pod)
	case PolicyCostOptimized:
		selected = s.selectByCost(scored)
	default:
		selected = s.selectRoundRobin(scored)
	}

	if selected == nil {
		return nil, fmt.Errorf("failed to select node for pod %s/%s", pod.Namespace, pod.Name)
	}

	// Update node allocation
	selected.Allocated.CPU += pod.Resources.CPU
	selected.Allocated.Memory += pod.Resources.Memory
	selected.LastUsed = time.Now()

	return &ScheduleResult{
		NodeID:    selected.ID,
		NodeName:  selected.Name,
		Score:     selected.Score,
		Timestamp: time.Now(),
	}, nil
}

// filterNodes filters nodes that can fit the pod.
func (s *Scheduler) filterNodes(pod *PodSpec) []*Node {
	var candidates []*Node

	for _, node := range s.nodes {
		// Check if node is ready
		if !node.Ready || node.Unschedulable {
			continue
		}

		// Check resource availability
		if !s.hasResources(node, pod.Resources) {
			continue
		}

		// Check node selector
		if !s.matchesNodeSelector(node, pod.NodeSelector) {
			continue
		}

		candidates = append(candidates, node)
	}

	return candidates
}

// hasResources checks if node has enough resources.
func (s *Scheduler) hasResources(node *Node, resources Resources) bool {
	availableCPU := node.Allocatable.CPU - node.Allocated.CPU
	availableMemory := node.Allocatable.Memory - node.Allocated.Memory
	availableStorage := node.Allocatable.Storage - node.Allocated.Storage

	if resources.CPU > availableCPU {
		return false
	}
	if resources.Memory > availableMemory {
		return false
	}
	if resources.Storage > availableStorage {
		return false
	}
	if resources.GPU > node.Allocatable.GPU {
		return false
	}

	return true
}

// matchesNodeSelector checks if node matches node selector.
func (s *Scheduler) matchesNodeSelector(node *Node, selector map[string]string) bool {
	for key, value := range selector {
		if nodeValue, ok := node.Labels[key]; !ok || nodeValue != value {
			return false
		}
	}
	return true
}

// scoreNodes scores nodes based on various factors.
func (s *Scheduler) scoreNodes(nodes []*Node, pod *PodSpec) []*Node {
	for _, node := range nodes {
		score := 0

		// Prefer nodes with more available resources
		cpuUsage := float64(node.Allocated.CPU) / float64(node.Allocatable.CPU)
		memoryUsage := float64(node.Allocated.Memory) / float64(node.Allocatable.Memory)
		score += int((1.0 - (cpuUsage+memoryUsage)/2.0) * 50)

		// Prefer nodes that haven't been used recently
		if time.Since(node.LastUsed) > 5*time.Minute {
			score += 10
		}

		// Apply affinity scoring
		if pod.Affinity != nil {
			score += s.scoreAffinity(node, pod.Affinity)
		}

		node.Score = score
	}

	return nodes
}

// scoreAffinity scores based on affinity rules.
func (s *Scheduler) scoreAffinity(node *Node, affinity *Affinity) int {
	score := 0

	if affinity.NodeAffinity != nil && affinity.NodeAffinity.Preferred != nil {
		for _, preferred := range affinity.NodeAffinity.Preferred {
			if s.matchesNodeSelectorTerm(node, preferred.Term) {
				score += preferred.Weight
			}
		}
	}

	return score
}

// matchesNodeSelectorTerm checks if node matches a selector term.
func (s *Scheduler) matchesNodeSelectorTerm(node *Node, term NodeSelectorTerm) bool {
	// Check match labels
	for key, value := range term.MatchLabels {
		if nodeValue, ok := node.Labels[key]; !ok || nodeValue != value {
			return false
		}
	}

	// Check match expressions (simplified)
	for _, expr := range term.MatchExpressions {
		nodeValue, ok := node.Labels[expr.Key]
		switch expr.Operator {
		case "In":
			if !ok || !contains(expr.Values, nodeValue) {
				return false
			}
		case "NotIn":
			if ok && contains(expr.Values, nodeValue) {
				return false
			}
		case "Exists":
			if !ok {
				return false
			}
		case "DoesNotExist":
			if ok {
				return false
			}
		}
	}

	return true
}

// selectRoundRobin selects node using round-robin.
func (s *Scheduler) selectRoundRobin(nodes []*Node) *Node {
	if len(nodes) == 0 {
		return nil
	}
