// Package middleware provides HTTP middleware for the AgentCube platform.
// AR-012: Request Validation Layer - Direct Handler approach with go-playground/validator
package middleware

import (
	"fmt"
	"net/http"
	"reflect"
	"regexp"
	"strings"

	"github.com/gin-gonic/gin"
	"github.com/go-playground/validator/v10"
)

// Validator is the global validator instance with custom validations.
var Validator *validator.Validate

func init() {
	Validator = validator.New()
	Validator.RegisterValidation("image_ref", validateImageRef)
	Validator.RegisterValidation("dns_label", validateDNSLabel)
	Validator.RegisterValidation("session_id", validateSessionID)
}

// validateImageRef validates container image references.
func validateImageRef(fl validator.FieldLevel) bool {
	image := fl.Field().String()
	if image == "" {
		return true
	}
	// Basic image ref validation: name[:tag] or name@digest
	// Supports registry.io/name:tag format
	imageRefRegex := regexp.MustCompile(`^([a-zA-Z0-9][-a-zA-Z0-9._]*([/][a-zA-Z0-9][-a-zA-Z0-9._]*)*)` +
		`([:]([a-zA-Z0-9][-a-zA-Z0-9._]*))?$`)
	return imageRefRegex.MatchString(image)
}

// validateDNSLabel validates Kubernetes DNS label format.
func validateDNSLabel(fl validator.FieldLevel) bool {
	label := fl.Field().String()
	if label == "" {
		return true
	}
	// DNS label rules: lowercase alphanumeric with hyphens, max 63 chars
	dnsLabelRegex := regexp.MustCompile(`^[a-z0-9]([-a-z0-9]*[a-z0-9])?$`)
	return dnsLabelRegex.MatchString(label) && len(label) <= 63
}

// validateSessionID validates session ID format.
func validateSessionID(fl validator.FieldLevel) bool {
	sessionID := fl.Field().String()
	if sessionID == "" {
		return true
	}
	// Session ID: alphanumeric with hyphens and underscores, 1-128 chars
	sessionIDRegex := regexp.MustCompile(`^[a-zA-Z0-9_-]+$`)
	return sessionIDRegex.MatchString(sessionID) && len(sessionID) <= 128
}

// ValidationMiddleware provides request validation middleware.
type ValidationMiddleware struct {
	validator *validator.Validate
}

// NewValidationMiddleware creates a new validation middleware.
func NewValidationMiddleware() *ValidationMiddleware {
	return &ValidationMiddleware{
		validator: Validator,
	}
}

// ValidationError represents a single validation error.
type ValidationError struct {
	Field   string `json:"field"`
	Tag     string `json:"tag"`
	Value   string `json:"value"`
	Message string `json:"message"`
}

// ValidationErrorResponse represents the validation error response.
type ValidationErrorResponse struct {
	Error   string            `json:"error"`
	Details []ValidationError `json:"details,omitempty"`
}

// Middleware returns the Gin middleware function for validation setup.
func (vm *ValidationMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Store validator in context for handlers to use
		c.Set("validator", vm.validator)
		c.Next()
	}
}

// ValidateRequest validates a request struct and returns validation errors.
func (vm *ValidationMiddleware) ValidateRequest(req interface{}) []ValidationError {
	return ValidateStruct(req)
}

// ValidateStruct validates a struct and returns validation errors.
func ValidateStruct(req interface{}) []ValidationError {
	err := Validator.Struct(req)
	if err == nil {
		return nil
	}

	var errors []ValidationError
	if validationErrors, ok := err.(validator.ValidationErrors); ok {
		for _, e := range validationErrors {
			fieldName := getJSONFieldName(req, e.Field())
			errors = append(errors, ValidationError{
				Field:   fieldName,
				Tag:     e.Tag(),
				Value:   fmt.Sprintf("%v", e.Value()),
				Message: getValidationMessage(e),
			})
		}
	}
	return errors
}

// getJSONFieldName gets the JSON field name from the struct tag.
func getJSONFieldName(req interface{}, fieldName string) string {
	t := reflect.TypeOf(req)
	if t.Kind() == reflect.Ptr {
		t = t.Elem()
	}

	field, found := t.FieldByName(fieldName)
	if !found {
		return strings.ToLower(fieldName)
	}

	jsonTag := field.Tag.Get("json")
	if jsonTag == "" || jsonTag == "-" {
		return strings.ToLower(fieldName)
	}

	// Extract just the name part before any options
	parts := strings.Split(jsonTag, ",")
	return strings.TrimSpace(parts[0])
}

// getValidationMessage returns a human-readable validation message.
func getValidationMessage(e validator.FieldError) string {
	switch e.Tag() {
	case "required":
		return fmt.Sprintf("Field '%s' is required", e.Field())
	case "min":
		return fmt.Sprintf("Field '%s' must be at least %s", e.Field(), e.Param())
	case "max":
		return fmt.Sprintf("Field '%s' must be at most %s", e.Field(), e.Param())
	case "image_ref":
		return fmt.Sprintf("Field '%s' must be a valid image reference", e.Field())
	case "dns_label":
		return fmt.Sprintf("Field '%s' must be a valid DNS label", e.Field())
	case "session_id":
		return fmt.Sprintf("Field '%s' must be a valid session ID", e.Field())
	case "email":
		return fmt.Sprintf("Field '%s' must be a valid email address", e.Field())
	case "url":
		return fmt.Sprintf("Field '%s' must be a valid URL", e.Field())
	default:
		return fmt.Sprintf("Field '%s' failed validation on tag '%s'", e.Field(), e.Tag())
	}
}

// AbortWithValidation aborts the request with validation errors.
func AbortWithValidation(c *gin.Context, errors []ValidationError) {
	c.JSON(http.StatusBadRequest, ValidationErrorResponse{
		Error:   "validation failed",
		Details: errors,
	})
	c.Abort()
}

// Common request structures with validation tags.

// CreateSandboxRequest represents a sandbox creation request.
type CreateSandboxRequest struct {
	Name        string            `json:"name" validate:"required,min=1,max=63,dns_label"`
	Namespace   string            `json:"namespace" validate:"required,min=1,max=63,dns_label"`
	Image       string            `json:"image" validate:"required,image_ref"`
	Kind        string            `json:"kind" validate:"required,oneof=AgentRuntime CodeInterpreter"`
	Timeout     int               `json:"timeout" validate:"min=60,max=3600"`
	SessionID   string            `json:"session_id,omitempty" validate:"omitempty,session_id"`
	Labels      map[string]string `json:"labels,omitempty" validate:"omitempty,dive,max=63"`
	Annotations map[string]string `json:"annotations,omitempty" validate:"omitempty"`
	EntryPoints []EntryPointSpec  `json:"entry_points,omitempty" validate:"omitempty,min=1,max=10,dive"`
}

